{
  "name": "VN Notes",
  "description": "Một ứng dụng ghi chú đơn giản, hiện đại giống Apple Notes, tích hợp AI để hỗ trợ viết và tóm tắt nội dung."
}

export interface Note {
  id: string;
  title: string;
  content: string;
  updatedAt: number;
}

export enum AIAction {
  SUMMARIZE = 'summarize',
  FIX_GRAMMAR = 'fix_grammar',
  CONTINUE_WRITING = 'continue_writing'
}

import { GoogleGenAI } from "@google/genai";
import { AIAction } from "../types";

const apiKey = process.env.API_KEY || '';

// Initialize the client only if the key is available to avoid immediate errors, 
// though actual calls will fail if missing.
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-3-flash-preview';

export const processTextWithAI = async (text: string, action: AIAction): Promise<string> => {
  if (!text.trim()) return '';
  if (!apiKey) throw new Error("API Key chưa được cấu hình.");

  let systemInstruction = "Bạn là một trợ lý viết lách thông minh bằng tiếng Việt.";
  let prompt = "";

  switch (action) {
    case AIAction.SUMMARIZE:
      prompt = `Hãy tóm tắt ngắn gọn nội dung sau đây (trả về kết quả tóm tắt): \n\n${text}`;
      break;
    case AIAction.FIX_GRAMMAR:
      prompt = `Hãy kiểm tra và sửa lỗi chính tả, ngữ pháp cho văn bản sau, giữ nguyên ý nghĩa gốc nhưng làm văn phong tự nhiên hơn (trả về văn bản đã sửa): \n\n${text}`;
      break;
    case AIAction.CONTINUE_WRITING:
      prompt = `Dựa trên nội dung sau, hãy viết tiếp một đoạn ngắn phù hợp với mạch văn (trả về phần viết tiếp): \n\n${text}`;
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction,
      }
    });

    return response.text || "";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useMemo } from 'react';
import { Note } from '../types';
import { Plus, Search, Trash2, FileText } from 'lucide-react';

interface SidebarProps {
  notes: Note[];
  activeNoteId: string | null;
  onSelectNote: (id: string) => void;
  onAddNote: () => void;
  onDeleteNote: (id: string, e: React.MouseEvent) => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({
  notes,
  activeNoteId,
  onSelectNote,
  onAddNote,
  onDeleteNote,
  searchQuery,
  onSearchChange,
}) => {

  const sortedAndFilteredNotes = useMemo(() => {
    return notes
      .filter((note) => {
        const query = searchQuery.toLowerCase();
        return (
          note.title.toLowerCase().includes(query) ||
          note.content.toLowerCase().includes(query)
        );
      })
      .sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, searchQuery]);

  const formatDate = (timestamp: number) => {
    return new Intl.DateTimeFormat('vi-VN', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    }).format(new Date(timestamp));
  };

  return (
    <div className="w-full md:w-80 bg-gray-50 border-r border-gray-200 flex flex-col h-full">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50 sticky top-0 z-10">
        <div className="flex justify-between items-center mb-4">
          <h1 className="text-xl font-bold text-gray-800">Ghi chú</h1>
          <button
            onClick={onAddNote}
            className="p-2 bg-yellow-400 hover:bg-yellow-500 text-yellow-900 rounded-full transition-colors shadow-sm"
            aria-label="Tạo ghi chú mới"
          >
            <Plus size={20} />
          </button>
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
          <input
            type="text"
            placeholder="Tìm kiếm..."
            value={searchQuery}
            onChange={(e) => onSearchChange(e.target.value)}
            className="w-full pl-9 pr-4 py-2 bg-gray-200/60 border-transparent focus:bg-white focus:ring-2 focus:ring-yellow-400/50 rounded-lg text-sm transition-all outline-none text-gray-800 placeholder-gray-500"
          />
        </div>
      </div>

      {/* Note List */}
      <div className="flex-1 overflow-y-auto no-scrollbar">
        {sortedAndFilteredNotes.length === 0 ? (
          <div className="p-8 text-center text-gray-400">
            <p className="text-sm">Không tìm thấy ghi chú nào.</p>
          </div>
        ) : (
          <ul className="divide-y divide-gray-100">
            {sortedAndFilteredNotes.map((note) => (
              <li
                key={note.id}
                onClick={() => onSelectNote(note.id)}
                className={`group cursor-pointer p-4 transition-all duration-200 hover:bg-gray-100 ${
                  activeNoteId === note.id ? 'bg-white border-l-4 border-yellow-400 shadow-sm' : 'border-l-4 border-transparent'
                }`}
              >
                <div className="flex justify-between items-start">
                  <h3 className={`font-semibold text-sm mb-1 truncate pr-2 ${activeNoteId === note.id ? 'text-gray-900' : 'text-gray-700'}`}>
                    {note.title || 'Ghi chú chưa đặt tên'}
                  </h3>
                  {activeNoteId === note.id && (
                     <button
                     onClick={(e) => onDeleteNote(note.id, e)}
                     className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                     title="Xóa ghi chú"
                   >
                     <Trash2 size={14} />
                   </button>
                  )}
                </div>
                <div className="flex gap-2 text-xs text-gray-500">
                  <span className="flex-shrink-0 font-medium">{formatDate(note.updatedAt)}</span>
                  <span className="truncate text-gray-400">
                    {note.content.replace(/\n/g, ' ') || 'Chưa có nội dung bổ sung'}
                  </span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>

      <div className="p-3 border-t border-gray-200 text-xs text-center text-gray-400 bg-gray-50">
        {notes.length} ghi chú
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Note, AIAction } from '../types';
import { Clock, Wand2, Check, Loader2, ArrowLeft } from 'lucide-react';
import { processTextWithAI } from '../services/geminiService';

interface EditorProps {
  note: Note;
  onUpdateNote: (id: string, updates: Partial<Note>) => void;
  onBack: () => void; // For mobile
}

export const Editor: React.FC<EditorProps> = ({ note, onUpdateNote, onBack }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showAiMenu, setShowAiMenu] = useState(false);
  const aiMenuRef = useRef<HTMLDivElement>(null);

  // Close AI menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (aiMenuRef.current && !aiMenuRef.current.contains(event.target as Node)) {
        setShowAiMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onUpdateNote(note.id, { title: e.target.value, updatedAt: Date.now() });
  };

  const handleContentChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    onUpdateNote(note.id, { content: e.target.value, updatedAt: Date.now() });
  };

  const handleAIAction = async (action: AIAction) => {
    setShowAiMenu(false);
    setIsAiLoading(true);

    try {
      const result = await processTextWithAI(note.content, action);

      if (action === AIAction.CONTINUE_WRITING) {
        // Append
        const newContent = note.content + (note.content.endsWith(' ') ? '' : ' ') + result;
        onUpdateNote(note.id, { content: newContent, updatedAt: Date.now() });
      } else {
        // Replace or Append as a summary block? 
        // For grammar, replace. For summary, maybe append to top or bottom.
        // Let's implement a "Review" mode or just replace/append for simplicity in this demo.
        if (action === AIAction.SUMMARIZE) {
           const newContent = note.content + "\n\n--- Tóm tắt bởi AI ---\n" + result;
           onUpdateNote(note.id, { content: newContent, updatedAt: Date.now() });
        } else {
           // Fix Grammar - replace content
           onUpdateNote(note.id, { content: result, updatedAt: Date.now() });
        }
      }
    } catch (error) {
      alert("Có lỗi xảy ra khi gọi AI. Vui lòng kiểm tra API Key.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const formattedDate = new Intl.DateTimeFormat('vi-VN', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  }).format(new Date(note.updatedAt));

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Mobile Back Button */}
      <div className="md:hidden p-4 border-b border-gray-100 flex items-center text-yellow-600 cursor-pointer" onClick={onBack}>
        <ArrowLeft size={20} className="mr-1" />
        <span className="font-medium">Danh sách</span>
      </div>

      <div className="flex-1 flex flex-col max-w-3xl mx-auto w-full p-6 md:p-12 h-full overflow-hidden">

        {/* Date Display */}
        <div className="text-center text-gray-400 text-sm mb-6 flex items-center justify-center gap-1.5">
          <Clock size={14} />
          <span>{formattedDate}</span>
        </div>

        {/* Title Input */}
        <input
          type="text"
          value={note.title}
          onChange={handleTitleChange}
          placeholder="Tiêu đề"
          className="text-3xl md:text-4xl font-bold text-gray-900 placeholder-gray-300 border-none outline-none bg-transparent w-full mb-4"
        />

        {/* Content Textarea */}
        <textarea
          value={note.content}
          onChange={handleContentChange}
          placeholder="Bắt đầu viết..."
          className="flex-1 resize-none border-none outline-none text-lg text-gray-700 leading-relaxed placeholder-gray-300 w-full bg-transparent no-scrollbar"
        />
      </div>

      {/* Floating Action Button for AI */}
      <div className="absolute bottom-8 right-8" ref={aiMenuRef}>
        <div className={`flex flex-col-reverse gap-3 transition-all duration-300 mb-4 ${showAiMenu ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
          <button
            onClick={() => handleAIAction(AIAction.SUMMARIZE)}
            className="flex items-center gap-3 px-4 py-2 bg-white text-gray-700 rounded-lg shadow-lg border border-gray-100 hover:bg-gray-50 transition-colors whitespace-nowrap"
          >
            <span className="text-sm font-medium">Tóm tắt nội dung</span>
            <div className="w-6 h-6 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center text-xs font-bold">AI</div>
          </button>
          <button
            onClick={() => handleAIAction(AIAction.FIX_GRAMMAR)}
            className="flex items-center gap-3 px-4 py-2 bg-white text-gray-700 rounded-lg shadow-lg border border-gray-100 hover:bg-gray-50 transition-colors whitespace-nowrap"
          >
            <span className="text-sm font-medium">Sửa lỗi chính tả</span>
            <div className="w-6 h-6 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center text-xs font-bold">AI</div>
          </button>
           <button
            onClick={() => handleAIAction(AIAction.CONTINUE_WRITING)}
            className="flex items-center gap-3 px-4 py-2 bg-white text-gray-700 rounded-lg shadow-lg border border-gray-100 hover:bg-gray-50 transition-colors whitespace-nowrap"
          >
            <span className="text-sm font-medium">Viết tiếp ý tưởng</span>
            <div className="w-6 h-6 rounded-full bg-green-100 text-green-600 flex items-center justify-center text-xs font-bold">AI</div>
          </button>
        </div>

        <button
          onClick={() => setShowAiMenu(!showAiMenu)}
          disabled={isAiLoading}
          className={`group flex items-center justify-center w-14 h-14 rounded-full shadow-xl transition-all duration-300 ${
            showAiMenu ? 'bg-gray-900 rotate-45' : 'bg-yellow-400 hover:scale-110'
          }`}
        >
          {isAiLoading ? (
            <Loader2 className="animate-spin text-gray-800" size={24} />
          ) : (
            <Wand2 className={`transition-colors ${showAiMenu ? 'text-white' : 'text-yellow-900'}`} size={24} />
          )}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { Note } from './types';

// Helper to generate unique ID
const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('vn-notes-app-data');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return [];
      }
    }
    return [
      {
        id: 'welcome-note',
        title: 'Chào mừng đến với VN Notes',
        content: 'Đây là ứng dụng ghi chú đơn giản lấy cảm hứng từ Apple Notes.\n\nTính năng:\n- Tạo và quản lý ghi chú.\n- Tự động lưu.\n- Tích hợp Gemini AI để hỗ trợ viết (Sử dụng nút Đũa thần góc dưới phải).\n\nHãy thử tạo một ghi chú mới!',
        updatedAt: Date.now(),
      }
    ];
  });

  const [activeNoteId, setActiveNoteId] = useState<string | null>(notes.length > 0 ? notes[0].id : null);
  const [searchQuery, setSearchQuery] = useState('');

  // Mobile responsiveness
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Persistence
  useEffect(() => {
    localStorage.setItem('vn-notes-app-data', JSON.stringify(notes));
  }, [notes]);

  // Adjust sidebar for mobile on load and resize
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) {
        if (activeNoteId) setIsSidebarOpen(false);
      } else {
        setIsSidebarOpen(true);
      }
    };

    // Initial check
    if (window.innerWidth < 768 && activeNoteId) {
      setIsSidebarOpen(false);
    }

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [activeNoteId]);

  const addNote = () => {
    const newNote: Note = {
      id: generateId(),
      title: '',
      content: '',
      updatedAt: Date.now(),
    };
    setNotes([newNote, ...notes]);
    setActiveNoteId(newNote.id);
    // On mobile, switch to editor immediately
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const deleteNote = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmed = window.confirm("Bạn có chắc chắn muốn xóa ghi chú này?");
    if (!confirmed) return;

    const newNotes = notes.filter((n) => n.id !== id);
    setNotes(newNotes);
    if (activeNoteId === id) {
      setActiveNoteId(newNotes.length > 0 ? newNotes[0].id : null);
    }
  };

  const updateNote = (id: string, updates: Partial<Note>) => {
    setNotes((prevNotes) =>
      prevNotes.map((note) => (note.id === id ? { ...note, ...updates } : note))
    );
  };

  const handleSelectNote = (id: string) => {
    setActiveNoteId(id);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleBackToSidebar = () => {
    setIsSidebarOpen(true);
  };

  const activeNote = notes.find((n) => n.id === activeNoteId);

  return (
    <div className="flex h-screen overflow-hidden bg-white">
      {/* Sidebar - Conditional rendering for mobile */}
      <div className={`${isSidebarOpen ? 'w-full md:w-80' : 'hidden md:block w-80'} h-full flex-shrink-0 transition-all`}>
        <Sidebar
          notes={notes}
          activeNoteId={activeNoteId}
          onSelectNote={handleSelectNote}
          onAddNote={addNote}
          onDeleteNote={deleteNote}
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
        />
      </div>

      {/* Main Editor Area */}
      <div className={`flex-1 h-full ${!isSidebarOpen ? 'block' : 'hidden md:block'}`}>
        {activeNote ? (
          <Editor 
            note={activeNote} 
            onUpdateNote={updateNote} 
            onBack={handleBackToSidebar}
          />
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-gray-300 bg-white">
            <div className="w-24 h-24 mb-6 bg-gray-50 rounded-full flex items-center justify-center">
                <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="12" y1="18" x2="12" y2="18"></line><line x1="8" y1="14" x2="16" y2="14"></line></svg>
            </div>
            <p className="text-lg font-medium text-gray-400">Chọn hoặc tạo ghi chú mới</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

