import React, { useMemo } from 'react';
import { Note } from '../types';
import { Plus, Search, Trash2, FileText } from 'lucide-react';

interface SidebarProps {
  notes: Note[];
  activeNoteId: string | null;
  onSelectNote: (id: string) => void;
  onAddNote: () => void;
  onDeleteNote: (id: string, e: React.MouseEvent) => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({
  notes,
  activeNoteId,
  onSelectNote,
  onAddNote,
  onDeleteNote,
  searchQuery,
  onSearchChange,
}) => {

  const sortedAndFilteredNotes = useMemo(() => {
    return notes
      .filter((note) => {
        const query = searchQuery.toLowerCase();
        return (
          note.title.toLowerCase().includes(query) ||
          note.content.toLowerCase().includes(query)
        );
      })
      .sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, searchQuery]);

  const formatDate = (timestamp: number) => {
    const date = new Date(timestamp);
    const now = new Date();
    const isToday = date.toDateString() === now.toDateString();

    if (isToday) {
        return new Intl.DateTimeFormat('vi-VN', {
            hour: '2-digit',
            minute: '2-digit'
        }).format(date);
    }

    return new Intl.DateTimeFormat('vi-VN', {
      month: 'numeric',
      day: 'numeric',
    }).format(date);
  };

  return (
    <div className="w-full md:w-80 bg-[#F2F2F7] border-r border-gray-200/60 flex flex-col h-full">
      {/* Header */}
      <div className="px-5 pt-5 pb-3 bg-[#F2F2F7] sticky top-0 z-10">
        <div className="flex justify-between items-center mb-4">
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Ghi chú</h1>
          <button
            onClick={onAddNote}
            className="p-2 bg-yellow-400 hover:bg-yellow-500 text-yellow-950 rounded-full transition-all shadow-sm hover:shadow-md active:scale-95"
            aria-label="Tạo ghi chú mới"
          >
            <Plus size={22} />
          </button>
        </div>
        <div className="relative group">
          <Search className="absolute left-3 top-2.5 text-gray-400 group-focus-within:text-yellow-500 transition-colors" size={16} />
          <input
            type="text"
            placeholder="Tìm kiếm"
            value={searchQuery}
            onChange={(e) => onSearchChange(e.target.value)}
            className="w-full pl-9 pr-4 py-2 bg-[#E3E3E8] focus:bg-white border-none focus:ring-2 focus:ring-yellow-400/30 rounded-xl text-[15px] transition-all outline-none text-gray-800 placeholder-gray-500"
          />
        </div>
      </div>

      {/* Note List */}
      <div className="flex-1 overflow-y-auto no-scrollbar px-3 pb-4">
        {sortedAndFilteredNotes.length === 0 ? (
          <div className="p-8 text-center text-gray-400">
            <p className="text-sm">Không tìm thấy ghi chú nào.</p>
          </div>
        ) : (
          <ul className="space-y-1">
            {sortedAndFilteredNotes.map((note) => (
              <li
                key={note.id}
                onClick={() => onSelectNote(note.id)}
                className={`group relative cursor-pointer p-4 rounded-xl transition-all duration-200 ${
                  activeNoteId === note.id 
                    ? 'bg-white shadow-sm ring-1 ring-black/5 z-10' 
                    : 'hover:bg-white/40 hover:shadow-sm'
                }`}
              >
                <div className="flex justify-between items-start mb-1">
                  <h3 className={`font-semibold text-[15px] truncate pr-6 ${activeNoteId === note.id ? 'text-gray-900' : 'text-gray-800'}`}>
                    {note.title.trim() || 'Ghi chú chưa đặt tên'}
                  </h3>
                   <button
                     onClick={(e) => onDeleteNote(note.id, e)}
                     className="absolute top-3 right-3 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1.5 hover:bg-gray-100 rounded-full"
                     title="Xóa ghi chú"
                   >
                     <Trash2 size={14} />
                   </button>
                </div>
                <div className="flex gap-2 text-xs items-center">
                  <span className={`flex-shrink-0 font-medium ${activeNoteId === note.id ? 'text-gray-500' : 'text-gray-500'}`}>
                      {formatDate(note.updatedAt)}
                  </span>
                  <span className="truncate text-gray-400 leading-relaxed">
                    {note.content.replace(/\n/g, ' ').trim() || 'Chưa có nội dung'}
                  </span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>

      <div className="p-3 border-t border-gray-200/50 text-[11px] font-medium text-center text-gray-400 bg-[#F2F2F7]">
        {notes.length} ghi chú
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Note, AIAction } from '../types';
import { Clock, Wand2, Check, Loader2, ArrowLeft } from 'lucide-react';
import { processTextWithAI } from '../services/geminiService';

interface EditorProps {
  note: Note;
  onUpdateNote: (id: string, updates: Partial<Note>) => void;
  onBack: () => void; // For mobile
}

export const Editor: React.FC<EditorProps> = ({ note, onUpdateNote, onBack }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showAiMenu, setShowAiMenu] = useState(false);
  const aiMenuRef = useRef<HTMLDivElement>(null);

  // Close AI menu when clicking outside
  useEffect(() => {
