import React, { useMemo } from 'react';
import { Note } from '../types';
import { Plus, Search, Trash2, FileText } from 'lucide-react';

interface SidebarProps {
  notes: Note[];
  activeNoteId: string | null;
  onSelectNote: (id: string) => void;
  onAddNote: () => void;
  onDeleteNote: (id: string, e: React.MouseEvent) => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({
  notes,
  activeNoteId,
  onSelectNote,
  onAddNote,
  onDeleteNote,
  searchQuery,
  onSearchChange,
}) => {

  const sortedAndFilteredNotes = useMemo(() => {
    return notes
      .filter((note) => {
        const query = searchQuery.toLowerCase();
        return (
          note.title.toLowerCase().includes(query) ||
          note.content.toLowerCase().includes(query)
        );
      })
      .sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, searchQuery]);

  const formatDate = (timestamp: number) => {
    const date = new Date(timestamp);
    const now = new Date();
    const isToday = date.toDateString() === now.toDateString();

    if (isToday) {
        return new Intl.DateTimeFormat('vi-VN', {
            hour: '2-digit',
            minute: '2-digit'
        }).format(date);
    }

    return new Intl.DateTimeFormat('vi-VN', {
      month: 'numeric',
      day: 'numeric',
    }).format(date);
  };

  return (
    <div className="w-full md:w-80 bg-[#F2F2F7] border-r border-gray-200/60 flex flex-col h-full">
      {/* Header */}
      <div className="px-5 pt-6 pb-4 bg-[#F2F2F7] sticky top-0 z-10">
        <div className="flex justify-between items-center mb-5">
          <h1 className="text-3xl font-bold text-gray-900 tracking-tight pl-1">Ghi chú</h1>
          <button
            onClick={onAddNote}
            className="p-3 bg-yellow-400 hover:bg-yellow-500 text-yellow-950 rounded-full transition-all active:scale-95 border border-yellow-500/10"
            aria-label="Tạo ghi chú mới"
          >
            <Plus size={22} />
          </button>
        </div>
        <div className="relative group">
          <Search className="absolute left-4 top-3 text-gray-400 group-focus-within:text-yellow-600 transition-colors" size={18} />
          <input
            type="text"
            placeholder="Tìm kiếm"
            value={searchQuery}
            onChange={(e) => onSearchChange(e.target.value)}
            className="w-full pl-11 pr-4 py-2.5 bg-[#E3E3E8] focus:bg-white border-none focus:ring-2 focus:ring-yellow-400/30 rounded-2xl text-[16px] transition-all outline-none text-gray-800 placeholder-gray-500"
          />
        </div>
      </div>

      {/* Note List */}
      <div className="flex-1 overflow-y-auto no-scrollbar px-4 pb-4">
        {sortedAndFilteredNotes.length === 0 ? (
          <div className="p-8 text-center text-gray-400">
            <p className="text-sm">Không tìm thấy ghi chú nào.</p>
          </div>
        ) : (
          <ul className="space-y-2">
            {sortedAndFilteredNotes.map((note) => (
              <li
                key={note.id}
                onClick={() => onSelectNote(note.id)}
                className={`group relative cursor-pointer p-5 rounded-3xl transition-all duration-200 ${
                  activeNoteId === note.id 
                    ? 'bg-white ring-1 ring-black/5 z-10' 
                    : 'hover:bg-white/50'
                }`}
              >
                <div className="flex justify-between items-start mb-1.5">
                  <h3 className={`font-bold text-[16px] truncate pr-6 ${activeNoteId === note.id ? 'text-gray-900' : 'text-gray-800'}`}>
                    {note.title.trim() || 'Ghi chú chưa đặt tên'}
                  </h3>
                   <button
                     onClick={(e) => onDeleteNote(note.id, e)}
                     className="absolute top-4 right-4 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1.5 hover:bg-gray-100 rounded-full"
                     title="Xóa ghi chú"
                   >
                     <Trash2 size={16} />
                   </button>
                </div>
                <div className="flex gap-3 text-xs items-center">
                  <span className={`flex-shrink-0 font-medium ${activeNoteId === note.id ? 'text-gray-500' : 'text-gray-500'}`}>
                      {formatDate(note.updatedAt)}
                  </span>
                  <span className="truncate text-gray-400 leading-relaxed font-medium">
                    {note.content.replace(/\n/g, ' ').trim() || 'Chưa có nội dung'}
                  </span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>

      <div className="p-4 border-t border-gray-200/50 text-[11px] font-semibold text-center text-gray-400 bg-[#F2F2F7]">
        {notes.length} ghi chú
      </div>
    </div>
  );
};

