import React, { useMemo } from 'react';
import { Note } from '../types';
import { Plus, Search, Trash2, FileText } from 'lucide-react';

interface SidebarProps {
  notes: Note[];
  activeNoteId: string | null;
  onSelectNote: (id: string) => void;
  onAddNote: () => void;
  onDeleteNote: (id: string, e: React.MouseEvent) => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({
  notes,
  activeNoteId,
  onSelectNote,
  onAddNote,
  onDeleteNote,
  searchQuery,
  onSearchChange,
}) => {

  const sortedAndFilteredNotes = useMemo(() => {
    return notes
      .filter((note) => {
        const query = searchQuery.toLowerCase();
        return (
          note.title.toLowerCase().includes(query) ||
          note.content.toLowerCase().includes(query)
        );
      })
      .sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, searchQuery]);

  const formatDate = (timestamp: number) => {
    const date = new Date(timestamp);
    const now = new Date();
    const isToday = date.toDateString() === now.toDateString();

    if (isToday) {
        return new Intl.DateTimeFormat('vi-VN', {
            hour: '2-digit',
            minute: '2-digit'
        }).format(date);
    }

    return new Intl.DateTimeFormat('vi-VN', {
      month: 'numeric',
      day: 'numeric',
    }).format(date);
  };

  return (
    <div className="w-full md:w-80 bg-[#F2F2F7] border-r border-gray-200/60 flex flex-col h-full">
      {/* Header */}
      <div className="px-5 pt-6 pb-2 bg-[#F2F2F7] sticky top-0 z-10">
        <div className="flex justify-between items-center mb-2">
          <h1 className="text-3xl font-bold text-gray-900 tracking-tight pl-1">Ghi chú</h1>
          <button
            onClick={onAddNote}
            className="p-3 bg-yellow-400 hover:bg-yellow-500 text-yellow-950 rounded-full transition-all active:scale-95 border border-yellow-500/10"
            aria-label="Tạo ghi chú mới"
          >
            <Plus size={22} />
          </button>
        </div>
      </div>

      {/* Note List */}
      <div className="flex-1 overflow-y-auto no-scrollbar px-4 pb-4">
        {sortedAndFilteredNotes.length === 0 ? (
          <div className="p-8 text-center text-gray-400">
            <p className="text-sm">Không tìm thấy ghi chú nào.</p>
          </div>
        ) : (
          <ul className="space-y-2">
            {sortedAndFilteredNotes.map((note) => (
              <li
                key={note.id}
                onClick={() => onSelectNote(note.id)}
                className={`group relative cursor-pointer p-5 rounded-3xl transition-all duration-200 ${
                  activeNoteId === note.id 
                    ? 'bg-white ring-1 ring-black/5 z-10' 
                    : 'hover:bg-white/50'
                }`}
              >
                <div className="flex justify-between items-start mb-1.5">
                  <h3 className={`font-bold text-[16px] truncate pr-6 ${activeNoteId === note.id ? 'text-gray-900' : 'text-gray-800'}`}>
