  const folderStats = useMemo(() => {
    const stats: Record<string, number> = {};
    let uncategorizedCount = 0;

    notes.forEach(note => {
      if (note.folder) {
        stats[note.folder] = (stats[note.folder] || 0) + 1;
      } else {
        uncategorizedCount++;
      }
    });

    const result = Object.entries(stats).map(([name, count]) => ({ name, count }));
    if (uncategorizedCount > 0) {
      result.push({ name: 'Chung', count: uncategorizedCount });
    }
    // Always ensure we have at least these if empty to look nice
    if (result.length === 0) {
        result.push({ name: 'Cá nhân', count: 0 });
        result.push({ name: 'Công việc', count: 0 });
    }
    return result;
  }, [notes]);

  const recentNotes = useMemo(() => {
    return [...notes].sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes]);

  const formatDate = (timestamp: number) => {
    return new Intl.DateTimeFormat('vi-VN', {
      day: 'numeric',
      month: 'numeric',
      year: 'numeric'
