import React, { useMemo } from 'react';
import { Note } from '../types';
import { Plus, Search, Trash2, Home, LayoutGrid } from 'lucide-react';

interface SidebarProps {
  notes: Note[];
  activeNoteId: string | null;
  onSelectNote: (id: string) => void;
  onAddNote: () => void;
  onDeleteNote: (id: string, e: React.MouseEvent) => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  onGoHome: () => void; // New prop
}

export const Sidebar: React.FC<SidebarProps> = ({
  notes,
  activeNoteId,
  onSelectNote,
  onAddNote,
  onDeleteNote,
  searchQuery,
  onSearchChange,
  onGoHome,
}) => {

  const sortedAndFilteredNotes = useMemo(() => {
    return notes
      .filter((note) => {
        const query = searchQuery.toLowerCase();
        return (
          note.title.toLowerCase().includes(query) ||
          note.content.toLowerCase().includes(query)
        );
      })
      .sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, searchQuery]);

  const formatDate = (timestamp: number) => {
    const date = new Date(timestamp);
    const now = new Date();
    const isToday = date.toDateString() === now.toDateString();

    if (isToday) {
        return new Intl.DateTimeFormat('vi-VN', {
            hour: '2-digit',
            minute: '2-digit'
        }).format(date);
    }

    return new Intl.DateTimeFormat('vi-VN', {
      month: 'numeric',
      day: 'numeric',
    }).format(date);
  };

  return (
    <div className="w-full md:w-80 bg-[#F2F2F7] border-r border-gray-200/60 flex flex-col h-full">
      {/* Header */}
      <div className="px-5 pt-6 pb-2 bg-[#F2F2F7] sticky top-0 z-10">
        <div className="flex justify-between items-center mb-4">
           {/* Home Button Group */}
           <div className="flex items-center gap-2">
              <button 
                onClick={onGoHome}
                className={`p-2 rounded-xl transition-all ${activeNoteId === null ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:bg-gray-200/50'}`}
                title="Tổng quan"
              >
                  <LayoutGrid size={20} />
              </button>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Ghi chú</h1>
           </div>

          <button
            onClick={onAddNote}
            className="p-2.5 bg-yellow-400 hover:bg-yellow-500 text-yellow-950 rounded-full transition-all active:scale-95 border border-yellow-500/10 shadow-sm"
            aria-label="Tạo ghi chú mới"
          >
            <Plus size={20} />
          </button>
        </div>
      </div>

      {/* Note List */}
      <div className="flex-1 overflow-y-auto no-scrollbar px-4 pb-4">
        {sortedAndFilteredNotes.length === 0 ? (
          <div className="p-8 text-center text-gray-400">
            <p className="text-sm">Không tìm thấy ghi chú nào.</p>
          </div>
        ) : (
          <ul className="space-y-2">
            {sortedAndFilteredNotes.map((note) => (
              <li
                key={note.id}
                onClick={() => onSelectNote(note.id)}
                className={`group relative cursor-pointer p-4 rounded-2xl transition-all duration-200 ${
                  activeNoteId === note.id 
                    ? 'bg-white shadow-sm ring-1 ring-black/5 z-10' 
                    : 'hover:bg-white/60'
                }`}
              >
                <div className="flex justify-between items-start mb-1">
                  <h3 className={`font-bold text-[15px] truncate pr-6 ${activeNoteId === note.id ? 'text-gray-900' : 'text-gray-800'}`}>
                    {note.title.trim() || 'Ghi chú chưa đặt tên'}
                  </h3>
                   <button
                     onClick={(e) => onDeleteNote(note.id, e)}
                     className="absolute top-4 right-4 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-1 hover:bg-gray-100 rounded-full"
                     title="Xóa ghi chú"
                   >
                     <Trash2 size={14} />
                   </button>
                </div>
                <div className="flex gap-2 text-xs items-center">
                  <span className={`flex-shrink-0 font-medium ${activeNoteId === note.id ? 'text-gray-500' : 'text-gray-500'}`}>
                      {formatDate(note.updatedAt)}
                  </span>
                  <span className="truncate text-gray-400 leading-relaxed font-medium">
                    {note.content.replace(/\n/g, ' ').trim() || 'Chưa có nội dung'}
                  </span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>

      {/* Search Bar - Moved to Bottom */}
      <div className="p-4 bg-[#F2F2F7] border-t border-gray-200/50 z-10">
        <div className="relative group">
          <Search className="absolute left-4 top-3 text-gray-400 group-focus-within:text-gray-600 transition-colors" size={18} />
          <input
            type="text"
            placeholder="Tìm kiếm"
            value={searchQuery}
            onChange={(e) => onSearchChange(e.target.value)}
            className="w-full pl-11 pr-4 py-2.5 bg-[#E3E3E8] focus:bg-white border-none focus:ring-0 rounded-2xl text-[15px] transition-all outline-none text-gray-800 placeholder-gray-500"
          />
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { Dashboard } from './components/Dashboard';
import { Note } from './types';

// Helper to generate unique ID
const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('vn-notes-app-data');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return [];
      }
    }
    return [
      {
        id: 'welcome-note',
        title: 'Chào mừng đến với VN Notes',
        content: 'Đây là ứng dụng ghi chú đơn giản lấy cảm hứng từ Apple Notes.\n\nTính năng:\n- Tạo và quản lý ghi chú.\n- Tự động lưu.\n- Tích hợp Gemini AI để hỗ trợ viết (Sử dụng nút Đũa thần góc dưới phải).\n\nHãy thử tạo một ghi chú mới!',
        updatedAt: Date.now(),
        folder: 'Cá nhân'
      },
      {
        id: 'ideas-note',
        title: 'Ý tưởng dự án mới',
        content: '- Tích hợp Voice to Text\n- Chế độ tối (Dark Mode)\n- Chia sẻ ghi chú qua link',
        updatedAt: Date.now() - 100000,
        folder: 'Công việc'
      }
    ];
  });

  // Start with null to show Dashboard by default
  const [activeNoteId, setActiveNoteId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Mobile responsiveness
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Persistence
  useEffect(() => {
    localStorage.setItem('vn-notes-app-data', JSON.stringify(notes));
  }, [notes]);

  // Adjust sidebar for mobile on load and resize
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) {
        if (activeNoteId) setIsSidebarOpen(false);
      } else {
        setIsSidebarOpen(true);
      }
    };

    // Initial check
    if (window.innerWidth < 768 && activeNoteId) {
      setIsSidebarOpen(false);
    }

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [activeNoteId]);

  const addNote = () => {
    const newNote: Note = {
      id: generateId(),
      title: '',
      content: '',
      updatedAt: Date.now(),
      folder: 'Chung' // Default folder
    };
    setNotes([newNote, ...notes]);
    setActiveNoteId(newNote.id);
    // On mobile, switch to editor immediately
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const deleteNote = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmed = window.confirm("Bạn có chắc chắn muốn xóa ghi chú này?");
    if (!confirmed) return;

    const newNotes = notes.filter((n) => n.id !== id);
    setNotes(newNotes);
    if (activeNoteId === id) {
      setActiveNoteId(null); // Go back to dashboard if deleting active note
    }
  };

  const updateNote = (id: string, updates: Partial<Note>) => {
    setNotes((prevNotes) =>
      prevNotes.map((note) => (note.id === id ? { ...note, ...updates } : note))
    );
  };

  const handleSelectNote = (id: string) => {
    setActiveNoteId(id);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleBackToSidebar = () => {
    setIsSidebarOpen(true);
    // On mobile, back button usually implies going up a level. 
    // Since we have Sidebar -> Editor, back shows Sidebar.
  };

  const handleGoHome = () => {
      setActiveNoteId(null);
      setIsSidebarOpen(true);
  };

  const activeNote = notes.find((n) => n.id === activeNoteId);

  return (
    <div className="flex h-screen overflow-hidden bg-white">
      {/* Sidebar - Conditional rendering for mobile */}
      <div className={`${isSidebarOpen ? 'w-full md:w-80' : 'hidden md:block w-80'} h-full flex-shrink-0 transition-all`}>
        <Sidebar
          notes={notes}
          activeNoteId={activeNoteId}
          onSelectNote={handleSelectNote}
          onAddNote={addNote}
          onDeleteNote={deleteNote}
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          onGoHome={handleGoHome}
        />
      </div>

      {/* Main Area: Shows Editor if note selected, otherwise Dashboard */}
      <div className={`flex-1 h-full ${!isSidebarOpen ? 'block' : 'hidden md:block'}`}>
        {activeNote ? (
          <Editor 
            note={activeNote} 
            onUpdateNote={updateNote} 
            onBack={handleBackToSidebar}
          />
        ) : (
          <Dashboard 
            notes={notes} 
            onSelectNote={handleSelectNote} 
          />
        )}
      </div>
    </div>
  );
};

