              </div>
            </div>

            <div className="flex gap-3 mt-10">
              <div className="flex-1"></div>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-6 py-4 rounded-xl text-gray-600 hover:bg-gray-100 font-bold transition-colors"
              >
                Hủy
              </button>
              <button 
                onClick={handleSave}
                disabled={!folderName.trim()}
                className="px-8 py-4 rounded-xl bg-blue-600 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-500/30 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {editingFolderId ? 'Lưu thay đổi' : 'Tạo thư mục'}
              </button>
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { Dashboard } from './components/Dashboard';
import { Note, Folder } from './types';

// Helper to generate unique ID
const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  // --- NOTES STATE ---
  const [notes, setNotes] = useState<Note[]>(() => {
    const saved = localStorage.getItem('vn-notes-app-data');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return [];
      }
    }
    return [
      {
        id: 'welcome-note',
        title: 'Chào mừng đến với VN Notes',
        content: 'Đây là ứng dụng ghi chú đơn giản lấy cảm hứng từ Apple Notes.\n\nTính năng:\n- Tạo và quản lý ghi chú.\n- Tự động lưu.\n- Tích hợp Gemini AI để hỗ trợ viết (Sử dụng nút Đũa thần góc dưới phải).\n\nHãy thử tạo một ghi chú mới!',
        updatedAt: Date.now(),
        folder: 'Cá nhân'
      },
      {
        id: 'ideas-note',
        title: 'Ý tưởng dự án mới',
        content: '- Tích hợp Voice to Text\n- Chế độ tối (Dark Mode)\n- Chia sẻ ghi chú qua link',
        updatedAt: Date.now() - 100000,
        folder: 'Công việc'
      }
    ];
  });

  // --- FOLDERS STATE ---
  const [folders, setFolders] = useState<Folder[]>(() => {
    const savedFolders = localStorage.getItem('vn-notes-app-folders');
    if (savedFolders) {
      try {
        return JSON.parse(savedFolders);
      } catch (e) {
        return [];
      }
    }
    // Default folders if none exist
    return [
      { id: 'f-personal', name: 'Cá nhân', color: 'bg-blue-500', icon: 'user' },
      { id: 'f-work', name: 'Công việc', color: 'bg-orange-500', icon: 'briefcase' },
    ];
  });

  // Navigation State
  const [activeNoteId, setActiveNoteId] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'dashboard' | 'trash'>('dashboard');
  const [searchQuery, setSearchQuery] = useState('');

  // Mobile responsiveness
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Persistence
  useEffect(() => {
    localStorage.setItem('vn-notes-app-data', JSON.stringify(notes));
  }, [notes]);

  useEffect(() => {
    localStorage.setItem('vn-notes-app-folders', JSON.stringify(folders));
  }, [folders]);

  // Adjust sidebar for mobile on load and resize
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) {
        if (activeNoteId) setIsSidebarOpen(false);
      } else {
        setIsSidebarOpen(true);
      }
    };

    // Initial check
    if (window.innerWidth < 768 && activeNoteId) {
      setIsSidebarOpen(false);
    }

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [activeNoteId]);

  // --- FILTERED DATA FOR UI ---
  // Only show non-deleted items in main views
  const activeNotes = useMemo(() => notes.filter(n => !n.deletedAt), [notes]);
  const activeFolders = useMemo(() => folders.filter(f => !f.deletedAt), [folders]);

  // Trash items
  const trashNotes = useMemo(() => notes.filter(n => n.deletedAt), [notes]);
  const trashFolders = useMemo(() => folders.filter(f => f.deletedAt), [folders]);

  // --- NOTE OPERATIONS ---

  const addNote = () => {
    const newNote: Note = {
      id: generateId(),
      title: '',
      content: '',
      updatedAt: Date.now(),
      folder: 'Chung' // Default folder
    };
    setNotes([newNote, ...notes]);
    setActiveNoteId(newNote.id);
    setCurrentView('dashboard'); // Switch back to dashboard context if in trash
    // On mobile, switch to editor immediately
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const deleteNote = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const isPermanent = currentView === 'trash';

    if (isPermanent) {
        if (window.confirm("Xóa vĩnh viễn ghi chú này? Hành động này không thể hoàn tác.")) {
            setNotes(prev => prev.filter(n => n.id !== id));
        }
    } else {
        // Soft delete
        setNotes(prev => prev.map(n => n.id === id ? { ...n, deletedAt: Date.now() } : n));
    }

    if (activeNoteId === id) {
      setActiveNoteId(null);
    }
  };

  const updateNote = (id: string, updates: Partial<Note>) => {
    setNotes((prevNotes) =>
      prevNotes.map((note) => (note.id === id ? { ...note, ...updates } : note))
    );
  };

  const handleSelectNote = (id: string) => {
    setActiveNoteId(id);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  // --- FOLDER OPERATIONS ---

  const addFolder = (folderData: Omit<Folder, 'id'>) => {
    const newFolder: Folder = {
      id: generateId(),
      ...folderData
    };
    setFolders([...folders, newFolder]);
  };

  const updateFolder = (id: string, updates: Partial<Folder>) => {
    const oldFolder = folders.find(f => f.id === id);

    setFolders(prevFolders => 
      prevFolders.map(f => f.id === id ? { ...f, ...updates } : f)
    );

    // If name changed, update all notes belonging to this folder
    if (oldFolder && updates.name && oldFolder.name !== updates.name) {
      setNotes(prevNotes => 
        prevNotes.map(n => 
          n.folder === oldFolder.name ? { ...n, folder: updates.name } : n
        )
      );
    }
  };

  const deleteFolder = (id: string) => {
    const folderToDelete = folders.find(f => f.id === id);
    if (!folderToDelete) return;

    // Moved to trash immediately without confirmation for better UX
    const timestamp = Date.now();

    // 1. Soft delete the folder
    setFolders(prev => prev.map(f => f.id === id ? { ...f, deletedAt: timestamp } : f));

    // 2. Soft delete all notes in that folder
    setNotes(prevNotes => 
    prevNotes.map(n => 
        n.folder === folderToDelete.name ? { ...n, deletedAt: timestamp } : n
    )
    );
  };

  // --- TRASH OPERATIONS ---

  const emptyTrash = () => {
      if (window.confirm("Bạn có chắc chắn muốn xóa vĩnh viễn tất cả mọi thứ trong thùng rác?")) {
          setNotes(prev => prev.filter(n => !n.deletedAt));
          setFolders(prev => prev.filter(f => !f.deletedAt));
      }
  };

  const restoreItem = (type: 'note' | 'folder', id: string) => {
      if (type === 'note') {
          setNotes(prev => prev.map(n => n.id === id ? { ...n, deletedAt: undefined } : n));
      } else {
          // Restore folder and its notes
          const folder = folders.find(f => f.id === id);
          if (folder) {
              setFolders(prev => prev.map(f => f.id === id ? { ...f, deletedAt: undefined } : f));
              // Ideally we only restore notes that were deleted at the same time, but for simplicity we restore all matching folder name
              // A better approach in a real app is to track transaction IDs.
              setNotes(prev => prev.map(n => n.folder === folder.name && n.deletedAt ? { ...n, deletedAt: undefined } : n));
          }
      }
  };

  // --- NAVIGATION ---

  const handleBackToSidebar = () => {
    setIsSidebarOpen(true);
  };

  const handleGoHome = () => {
      setActiveNoteId(null);
      setCurrentView('dashboard');
      setIsSidebarOpen(true);
  };

  const handleGoTrash = () => {
      setActiveNoteId(null);
      setCurrentView('trash');
      setIsSidebarOpen(true);
  };

  const activeNote = notes.find((n) => n.id === activeNoteId);

  return (
    <div className="flex h-screen overflow-hidden bg-white">
      {/* Sidebar - Conditional rendering for mobile */}
      <div className={`${isSidebarOpen ? 'w-full md:w-80' : 'hidden md:block w-80'} h-full flex-shrink-0 transition-all`}>
        <Sidebar
          notes={currentView === 'trash' ? trashNotes : activeNotes}
          activeNoteId={activeNoteId}
          onSelectNote={handleSelectNote}
          onAddNote={addNote}
          onDeleteNote={deleteNote}
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          onGoHome={handleGoHome}
          onGoTrash={handleGoTrash}
          currentView={currentView}
        />
      </div>

      {/* Main Area: Shows Editor if note selected, otherwise Dashboard */}
      <div className={`flex-1 h-full ${!isSidebarOpen ? 'block' : 'hidden md:block'}`}>
        {activeNote ? (
          <Editor 
            note={activeNote} 
            folders={activeFolders} // Only allow moving to active folders
            onUpdateNote={updateNote} 
            onBack={handleBackToSidebar}
          />
        ) : (
          <Dashboard 
            notes={currentView === 'trash' ? trashNotes : activeNotes} 
            folders={currentView === 'trash' ? trashFolders : activeFolders}
            onSelectNote={handleSelectNote} 
            onAddFolder={addFolder}
            onUpdateFolder={updateFolder}
            onDeleteFolder={deleteFolder}
            isTrashView={currentView === 'trash'}
            onEmptyTrash={emptyTrash}
            onRestoreItem={restoreItem}
          />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { Note, Folder as FolderType } from '../types';
import { 
  Folder, Clock, FileText, ChevronRight, Briefcase, User, 
  Heart, Star, Book, Coffee, Music, Layout, X,
  ArrowLeft, Trash2, PenLine, MoreHorizontal, Plus, RotateCcw
} from 'lucide-react';

interface DashboardProps {
  notes: Note[];
  folders: FolderType[];
  onSelectNote: (id: string) => void;
  onAddFolder: (folder: Omit<FolderType, 'id'>) => void;
  onUpdateFolder: (id: string, updates: Partial<FolderType>) => void;
  onDeleteFolder: (id: string) => void;
  isTrashView?: boolean;
  onEmptyTrash?: () => void;
  onRestoreItem?: (type: 'note' | 'folder', id: string) => void;
}

// Icon mapping
const ICON_MAP: Record<string, React.ElementType> = {
  folder: Folder,
  briefcase: Briefcase,
  user: User,
  heart: Heart,
  star: Star,
  book: Book,
  coffee: Coffee,
  music: Music,
  layout: Layout
};

// Vertical Gradient mapping: #f1f1f1 (top) -> color (bottom)
const GRADIENT_MAP: Record<string, string> = {
  blue: 'to-blue-100',
  orange: 'to-orange-100',
  green: 'to-green-100',
  red: 'to-red-100',
  purple: 'to-purple-100',
  pink: 'to-pink-100',
  gray: 'to-gray-200',
};

const TEXT_COLOR_MAP: Record<string, string> = {
  blue: 'text-blue-600',
  orange: 'text-orange-600',
  green: 'text-green-600',
  red: 'text-red-600',
  purple: 'text-purple-600',
  pink: 'text-pink-600',
  gray: 'text-gray-600',
};

// Classes for the color picker preview
const COLOR_OPTIONS = [
    { id: 'blue', class: 'bg-blue-500' },
    { id: 'orange', class: 'bg-orange-500' },
    { id: 'green', class: 'bg-green-500' },
    { id: 'red', class: 'bg-red-500' },
    { id: 'purple', class: 'bg-purple-500' },
    { id: 'pink', class: 'bg-pink-500' },
    { id: 'gray', class: 'bg-gray-500' },
];

export const Dashboard: React.FC<DashboardProps> = ({ 
  notes, 
  folders, 
  onSelectNote,
  onAddFolder,
  onUpdateFolder,
  onDeleteFolder,
  isTrashView = false,
  onEmptyTrash,
  onRestoreItem
}) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
  const [viewingFolder, setViewingFolder] = useState<string | null>(null);

  // State for the "More" dropdown menu
  const [openMenuFolderId, setOpenMenuFolderId] = useState<string | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Form State
  const [folderName, setFolderName] = useState('');
  const [selectedIcon, setSelectedIcon] = useState('folder');
  const [selectedColor, setSelectedColor] = useState('bg-blue-500');

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setOpenMenuFolderId(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Calculate folder statistics
  const folderStats = useMemo(() => {
    // Count notes per folder name
    const counts: Record<string, number> = {};
    let uncategorizedCount = 0;

    notes.forEach(note => {
      if (note.folder && note.folder !== 'Chung') {
        counts[note.folder] = (counts[note.folder] || 0) + 1;
      } else {
        uncategorizedCount++;
      }
    });

    // Map explicit folders to include counts
    const mappedFolders = folders.map(f => ({
      ...f,
      count: counts[f.name] || 0
    }));

    return {
      mapped: mappedFolders,
      uncategorized: uncategorizedCount
    };
  }, [notes, folders]);

  // Filter notes based on view (All or specific folder)
  const displayedNotes = useMemo(() => {
    let filtered = notes;

    if (viewingFolder === 'Chung') {
      filtered = notes.filter(n => !n.folder || n.folder === 'Chung');
    } else if (viewingFolder) {
      filtered = notes.filter(n => n.folder === viewingFolder);
    }

    return [...filtered].sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, viewingFolder]);

  const formatDate = (timestamp: number) => {
    return new Intl.DateTimeFormat('vi-VN', {
      day: 'numeric',
      month: 'numeric',
      year: 'numeric'
    }).format(new Date(timestamp));
  };

  const handleOpenModal = (folder?: FolderType) => {
    setOpenMenuFolderId(null); // Close menu if open
    if (folder) {
      setEditingFolderId(folder.id);
      setFolderName(folder.name);
      setSelectedIcon(folder.icon);
      setSelectedColor(folder.color);
    } else {
      setEditingFolderId(null);
      setFolderName('');
      setSelectedIcon('folder');
      setSelectedColor('bg-blue-500');
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!folderName.trim()) return;

    if (editingFolderId) {
      onUpdateFolder(editingFolderId, {
        name: folderName,
        icon: selectedIcon,
        color: selectedColor
      });
      if (viewingFolder && viewingFolder !== folderName) {
          setViewingFolder(folderName);
      }
    } else {
      onAddFolder({
        name: folderName,
        icon: selectedIcon,
        color: selectedColor
      });
    }
    setIsModalOpen(false);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setOpenMenuFolderId(null);
      onDeleteFolder(id);
      if (viewingFolder) setViewingFolder(null);
  };

  const handleRestoreClick = (e: React.MouseEvent, type: 'note' | 'folder', id: string) => {
      e.stopPropagation();
      setOpenMenuFolderId(null);
      if (onRestoreItem) onRestoreItem(type, id);
  };

  const handleEditClick = (e: React.MouseEvent, folder: FolderType) => {
      e.stopPropagation();
      handleOpenModal(folder);
  };

  const toggleMenu = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setOpenMenuFolderId(openMenuFolderId === id ? null : id);
  };

  return (
    <div className="relative h-full">
        <div className="h-full overflow-y-auto bg-gray-50/50 p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-12 pb-24">

                {/* Header */}
                <div>
                {viewingFolder ? (
                    <div className="flex items-center gap-4 mb-2">
                        <button 
                            onClick={() => setViewingFolder(null)}
                            className="p-2 rounded-full hover:bg-gray-200 transition-colors -ml-2 text-gray-600"
                        >
                            <ArrowLeft size={28} />
                        </button>
                        <h1 className="text-4xl font-bold text-gray-900 tracking-tight">{viewingFolder}</h1>
                    </div>
                ) : (
                    <div className="flex justify-between items-end">
                        <div>
                            <h1 className="text-4xl font-bold text-gray-900 mb-2 tracking-tight">
                                {isTrashView ? 'Thùng rác' : 'Tổng quan'}
                            </h1>
                            <p className="text-gray-500 text-lg">
                                {isTrashView 
                                    ? 'Các mục trong thùng rác có thể được khôi phục hoặc xóa vĩnh viễn.' 
                                    : <>Chào mừng trở lại, bạn có <span className="font-semibold text-gray-900">{notes.length}</span> ghi chú.</>
                                }
                            </p>
                        </div>
                    </div>
                )}
                </div>

                {/* Folders Section - Only show when NOT viewing a specific folder AND NOT in Trash view */}
                {!viewingFolder && !isTrashView && (
                    <section>
                    <div className="flex items-center justify-between mb-8">
                        <h2 className="text-xl font-semibold text-gray-800 flex items-center gap-2">
                        <Folder size={20} className="text-blue-500" />
                        Thư mục
                        </h2>
                    </div>

                    {/* Grid Layout: Adjusted for wider frames (3 cols on large instead of 4) */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">

                        {/* System/Uncategorized Folder */}
                        <div 
                            onClick={() => setViewingFolder('Chung')}
                            className="bg-gradient-to-b from-[#f1f1f1] to-gray-200 p-8 rounded-[2rem] hover:scale-[1.02] transition-all duration-300 cursor-pointer group flex flex-col justify-between h-64 border border-white/60 relative overflow-hidden"
                        >
                            <div className="flex justify-between items-start z-10">
                                    {/* Icon Left */}
                                <div className="w-14 h-14 rounded-2xl bg-white/80 backdrop-blur-sm text-gray-500 flex items-center justify-center">
                                    <Folder size={28} strokeWidth={2} />
                                </div>
                            </div>

                            <div className="flex justify-between items-end z-10">
                                    {/* Title Left */}
                                <div>
                                    <h3 className="text-2xl font-bold text-gray-800 truncate mb-1">Chung</h3>
                                    <p className="text-base text-gray-500 font-medium">Mặc định</p>
                                </div>

                                {/* Count Right */}
                                <span className="text-4xl font-bold text-gray-800/80">{folderStats.uncategorized}</span>
                            </div>
                        </div>

                        {/* User Folders */}
                        {folderStats.mapped.map((folder) => {
                        const IconComponent = ICON_MAP[folder.icon] || Folder;
                        const colorName = folder.color.split('-')[1] || 'gray';
                        const toColorClass = GRADIENT_MAP[colorName] || 'to-gray-100';
                        const iconColorClass = TEXT_COLOR_MAP[colorName] || 'text-gray-600';

                        const isMenuOpen = openMenuFolderId === folder.id;

                        return (
                            <div 
                            key={folder.id} 
                            onClick={() => setViewingFolder(folder.name)}
                            className={`bg-gradient-to-b from-[#f1f1f1] ${toColorClass} p-8 rounded-[2rem] hover:scale-[1.02] transition-all duration-300 cursor-pointer group relative flex flex-col justify-between h-64 border border-white/60`}
                            >
                                {/* Top Row */}
                                <div className="flex justify-between items-start">
                                    {/* Icon Left */}
                                    <div className={`w-14 h-14 rounded-2xl bg-white/60 backdrop-blur-sm ${iconColorClass} flex items-center justify-center group-hover:scale-105 transition-transform`}>
                                        <IconComponent size={28} strokeWidth={2} />
                                    </div>

                                    {/* Menu Button Right */}
                                    <div className="relative">
                                        <button 
                                            onClick={(e) => toggleMenu(e, folder.id)}
                                            className={`p-2 rounded-full hover:bg-white/80 transition-colors ${isMenuOpen ? 'bg-white/80 text-gray-800' : 'text-gray-400 hover:text-gray-600'}`}
                                        >
                                            <MoreHorizontal size={24} />
                                        </button>

                                        {/* Dropdown Menu */}
                                        {isMenuOpen && (
                                            <div ref={menuRef} className="absolute top-full right-0 mt-2 w-48 bg-white rounded-xl border border-gray-100 overflow-hidden z-20 animate-in fade-in zoom-in-95 duration-100 shadow-xl">
                                                <button 
                                                    onClick={(e) => handleEditClick(e, folder)}
                                                    className="w-full text-left px-5 py-3.5 text-[15px] text-gray-700 hover:bg-gray-50 flex items-center gap-3 font-medium"
                                                >
                                                    <PenLine size={18} /> Chỉnh sửa
                                                </button>
                                                <div className="h-px bg-gray-100 w-full"></div>
                                                <button 
                                                    onClick={(e) => handleDeleteClick(e, folder.id)}
                                                    className="w-full text-left px-5 py-3.5 text-[15px] text-red-600 hover:bg-red-50 flex items-center gap-3 font-medium"
                                                >
                                                    <Trash2 size={18} /> Xóa
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </div>

                                {/* Bottom Row */}
                                <div className="flex justify-between items-end">
                                    {/* Title Left */}
                                    <div>
                                        <h3 className="text-2xl font-bold text-gray-900 truncate pr-2 mb-1 max-w-[180px]">{folder.name}</h3>
                                        <p className="text-base text-gray-500 font-medium">{folder.count} ghi chú</p>
                                    </div>

                                    {/* Count Right - Large Number */}
                                    <span className="text-4xl font-bold text-gray-800/80">{folder.count}</span>
                                </div>
                            </div>
                        );
                        })}

                        {/* Add Folder Button */}
                        <div 
                            onClick={() => handleOpenModal()}
                            className="bg-[#fafafa] border-2 border-dashed border-gray-200 rounded-[2rem] p-8 flex flex-col items-center justify-center text-gray-400 hover:border-blue-300 hover:text-blue-500 hover:bg-blue-50/30 transition-all cursor-pointer h-64 gap-4 group"
                        >
                            <div className="w-16 h-16 rounded-full bg-white border border-gray-100 group-hover:bg-blue-100 group-hover:border-blue-200 flex items-center justify-center transition-colors">
                                <Plus size={32} />
                            </div>
                            <span className="font-semibold text-lg">Thư mục mới</span>
                        </div>
                    </div>
                    </section>
                )}

                {/* Notes Grid Section */}
                <section>
                {!isTrashView && (
                    <div className="flex items-center justify-between mb-6">
                        <h2 className="text-xl font-semibold text-gray-800 flex items-center gap-2">
                        <Clock size={20} className="text-orange-500" />
                        {viewingFolder ? `Ghi chú trong "${viewingFolder}"` : 'Tất cả ghi chú'}
                        </h2>
                    </div>
                )}

                {displayedNotes.length === 0 ? (
                    <div className="text-center py-16 bg-white rounded-3xl border border-gray-100">
                        <FileText className="w-16 h-16 text-gray-200 mx-auto mb-4" />
                        <p className="text-gray-400 text-lg">Không có ghi chú nào</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                    {displayedNotes.map((note) => (
                        <div 
                        key={note.id}
                        onClick={() => !isTrashView && onSelectNote(note.id)}
                        className={`bg-white p-6 rounded-3xl border border-gray-100 hover:-translate-y-1 transition-all flex flex-col h-56 group relative ${!isTrashView ? 'cursor-pointer hover:shadow-lg' : ''}`}
                        >
                        <div className="flex justify-between items-start mb-4">
                            <span className="text-[11px] font-bold tracking-wider text-gray-400 uppercase bg-gray-50 px-2 py-1 rounded-md max-w-[120px] truncate">
                                {note.folder || 'Chung'}
                            </span>
                            <span className="text-xs text-gray-400 font-medium">{formatDate(note.updatedAt)}</span>
                        </div>

                        <h3 className="font-bold text-xl text-gray-900 mb-3 truncate pr-2 group-hover:text-blue-600 transition-colors">
                            {note.title || 'Ghi chú chưa đặt tên'}
                        </h3>

                        <p className="text-gray-500 text-sm line-clamp-4 leading-relaxed flex-1">
                            {note.content || <span className="italic opacity-50">Không có nội dung...</span>}
                        </p>

                        {isTrashView ? (
                            <div className="mt-4 pt-4 border-t border-gray-50 flex justify-end gap-2">
                                <button 
                                    onClick={(e) => handleRestoreClick(e, 'note', note.id)}
                                    className="text-green-600 text-sm font-medium hover:underline"
                                >
                                    Khôi phục
                                </button>
                            </div>
                        ) : (
                            <div className="mt-4 pt-4 border-t border-gray-50 flex justify-end text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                <span className="text-xs font-semibold flex items-center">
                                    Mở ghi chú <ChevronRight size={14} className="ml-1" />
                                </span>
                            </div>
                        )}
                        </div>
                    ))}
                    </div>
                )}
                </section>
            </div>
        </div>

        {/* Empty Trash Button - Floating at bottom center */}
        {isTrashView && (notes.length > 0 || folders.length > 0) && (
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-30">
                <button 
                    onClick={onEmptyTrash}
                    className="w-16 h-16 bg-red-500 hover:bg-red-600 text-white rounded-full shadow-lg shadow-red-500/30 flex items-center justify-center transition-all hover:scale-110 active:scale-95 group"
                    title="Dọn sạch thùng rác"
                >
                    <Trash2 size={30} strokeWidth={2.5} className="group-hover:rotate-12 transition-transform" />
                </button>
            </div>
        )}

      {/* MODAL for Create/Edit Folder */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/20 backdrop-blur-sm">
          <div className="bg-white rounded-3xl w-full max-w-md p-8 animate-in fade-in zoom-in duration-200 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-bold text-gray-900">
                {editingFolderId ? 'Sửa thư mục' : 'Thư mục mới'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 p-2 rounded-full hover:bg-gray-100">
                <X size={24} />
              </button>
            </div>

            <div className="space-y-8">
              {/* Name Input */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Tên thư mục</label>
                <input 
                  type="text" 
                  value={folderName}
                  onChange={(e) => setFolderName(e.target.value)}
                  placeholder="Ví dụ: Du lịch, Ý tưởng..."
                  className="w-full px-5 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all text-lg"
                  autoFocus
                />
              </div>

              {/* Color Picker with Gradient Preview */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Màu sắc</label>
                <div className="grid grid-cols-7 gap-3">
                  {COLOR_OPTIONS.map((color) => {
                    const colorName = color.id;
                    const toColorClass = GRADIENT_MAP[colorName];
                    return (
                        <button
                        key={color.id}
                        onClick={() => setSelectedColor(color.class)}
                        className={`w-full aspect-square rounded-full bg-gradient-to-b from-[#f1f1f1] ${toColorClass} transition-transform hover:scale-110 border-2 ${selectedColor === color.class ? 'border-gray-400 scale-110' : 'border-transparent'}`}
                        title={colorName}
                        />
                    );
                  })}
                </div>
              </div>

              {/* Icon Picker */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Biểu tượng</label>
                <div className="grid grid-cols-5 gap-3">
                  {Object.entries(ICON_MAP).map(([name, Icon]) => (
                    <button
                      key={name}
                      onClick={() => setSelectedIcon(name)}
                      className={`p-3 rounded-2xl flex items-center justify-center transition-all ${selectedIcon === name ? 'bg-gray-100 text-gray-900 ring-2 ring-gray-200' : 'text-gray-400 hover:bg-gray-50'}`}
                    >
                      <Icon size={24} strokeWidth={2} />
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-10">
              <div className="flex-1"></div>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-6 py-4 rounded-xl text-gray-600 hover:bg-gray-100 font-bold transition-colors"
              >
                Hủy
              </button>
              <button 
                onClick={handleSave}
                disabled={!folderName.trim()}
                className="px-8 py-4 rounded-xl bg-blue-600 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-500/30 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {editingFolderId ? 'Lưu thay đổi' : 'Tạo thư mục'}
              </button>
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { Note, Folder as FolderType } from '../types';
import { 
  Folder, Clock, FileText, ChevronRight, Briefcase, User, 
  Heart, Star, Book, Coffee, Music, Layout, X,
  ArrowLeft, Trash2, PenLine, MoreHorizontal, Plus, RotateCcw
} from 'lucide-react';

interface DashboardProps {
  notes: Note[];
  folders: FolderType[];
  onSelectNote: (id: string) => void;
  onAddFolder: (folder: Omit<FolderType, 'id'>) => void;
  onUpdateFolder: (id: string, updates: Partial<FolderType>) => void;
  onDeleteFolder: (id: string) => void;
  isTrashView?: boolean;
  onEmptyTrash?: () => void;
  onRestoreItem?: (type: 'note' | 'folder', id: string) => void;
}

// Icon mapping
const ICON_MAP: Record<string, React.ElementType> = {
  folder: Folder,
  briefcase: Briefcase,
  user: User,
  heart: Heart,
  star: Star,
  book: Book,
  coffee: Coffee,
  music: Music,
  layout: Layout
};

// Vertical Gradient mapping: #f1f1f1 (top) -> color (bottom)
const GRADIENT_MAP: Record<string, string> = {
  blue: 'to-blue-100',
  orange: 'to-orange-100',
  green: 'to-green-100',
  red: 'to-red-100',
  purple: 'to-purple-100',
  pink: 'to-pink-100',
  gray: 'to-gray-200',
};

const TEXT_COLOR_MAP: Record<string, string> = {
  blue: 'text-blue-600',
  orange: 'text-orange-600',
  green: 'text-green-600',
  red: 'text-red-600',
  purple: 'text-purple-600',
  pink: 'text-pink-600',
  gray: 'text-gray-600',
};

// Classes for the color picker preview
const COLOR_OPTIONS = [
    { id: 'blue', class: 'bg-blue-500' },
    { id: 'orange', class: 'bg-orange-500' },
    { id: 'green', class: 'bg-green-500' },
    { id: 'red', class: 'bg-red-500' },
    { id: 'purple', class: 'bg-purple-500' },
    { id: 'pink', class: 'bg-pink-500' },
    { id: 'gray', class: 'bg-gray-500' },
];

export const Dashboard: React.FC<DashboardProps> = ({ 
  notes, 
  folders, 
  onSelectNote,
  onAddFolder,
  onUpdateFolder,
  onDeleteFolder,
  isTrashView = false,
  onEmptyTrash,
  onRestoreItem
}) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
  const [viewingFolder, setViewingFolder] = useState<string | null>(null);

  // State for the "More" dropdown menu
  const [openMenuFolderId, setOpenMenuFolderId] = useState<string | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Form State
  const [folderName, setFolderName] = useState('');
  const [selectedIcon, setSelectedIcon] = useState('folder');
  const [selectedColor, setSelectedColor] = useState('bg-blue-500');

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setOpenMenuFolderId(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Calculate folder statistics
  const folderStats = useMemo(() => {
    // Count notes per folder name
    const counts: Record<string, number> = {};
    let uncategorizedCount = 0;

    notes.forEach(note => {
      if (note.folder && note.folder !== 'Chung') {
        counts[note.folder] = (counts[note.folder] || 0) + 1;
      } else {
        uncategorizedCount++;
      }
    });

    // Map explicit folders to include counts
    const mappedFolders = folders.map(f => ({
      ...f,
      count: counts[f.name] || 0
    }));

    return {
      mapped: mappedFolders,
      uncategorized: uncategorizedCount
    };
  }, [notes, folders]);

  // Filter notes based on view (All or specific folder)
  const displayedNotes = useMemo(() => {
    let filtered = notes;

    if (viewingFolder === 'Chung') {
      filtered = notes.filter(n => !n.folder || n.folder === 'Chung');
    } else if (viewingFolder) {
      filtered = notes.filter(n => n.folder === viewingFolder);
    }

    return [...filtered].sort((a, b) => b.updatedAt - a.updatedAt);
  }, [notes, viewingFolder]);

  const formatDate = (timestamp: number) => {
    return new Intl.DateTimeFormat('vi-VN', {
      day: 'numeric',
      month: 'numeric',
      year: 'numeric'
    }).format(new Date(timestamp));
  };

  const handleOpenModal = (folder?: FolderType) => {
    setOpenMenuFolderId(null); // Close menu if open
    if (folder) {
      setEditingFolderId(folder.id);
      setFolderName(folder.name);
      setSelectedIcon(folder.icon);
      setSelectedColor(folder.color);
    } else {
      setEditingFolderId(null);
      setFolderName('');
      setSelectedIcon('folder');
      setSelectedColor('bg-blue-500');
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    if (!folderName.trim()) return;

    if (editingFolderId) {
      onUpdateFolder(editingFolderId, {
        name: folderName,
        icon: selectedIcon,
        color: selectedColor
      });
      if (viewingFolder && viewingFolder !== folderName) {
          setViewingFolder(folderName);
      }
    } else {
      onAddFolder({
        name: folderName,
        icon: selectedIcon,
        color: selectedColor
      });
    }
    setIsModalOpen(false);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setOpenMenuFolderId(null);
      onDeleteFolder(id);
      if (viewingFolder) setViewingFolder(null);
  };

  const handleRestoreClick = (e: React.MouseEvent, type: 'note' | 'folder', id: string) => {
      e.stopPropagation();
      setOpenMenuFolderId(null);
      if (onRestoreItem) onRestoreItem(type, id);
  };

  const handleEditClick = (e: React.MouseEvent, folder: FolderType) => {
      e.stopPropagation();
      handleOpenModal(folder);
  };

  const toggleMenu = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setOpenMenuFolderId(openMenuFolderId === id ? null : id);
  };

  return (
    <div className="relative h-full">
        <div className="h-full overflow-y-auto bg-gray-50/50 p-6 md:p-10">
            <div className="max-w-7xl mx-auto space-y-12 pb-24">

                {/* Header */}
                <div>
                {viewingFolder ? (
                    <div className="flex items-center gap-4 mb-2">
                        <button 
                            onClick={() => setViewingFolder(null)}
                            className="p-2 rounded-full hover:bg-gray-200 transition-colors -ml-2 text-gray-600"
                        >
                            <ArrowLeft size={28} />
                        </button>
                        <h1 className="text-4xl font-bold text-gray-900 tracking-tight">{viewingFolder}</h1>
                    </div>
                ) : (
                    <div className="flex justify-between items-end">
                        <div>
                            <h1 className="text-4xl font-bold text-gray-900 mb-2 tracking-tight">
                                {isTrashView ? 'Thùng rác' : 'Tổng quan'}
                            </h1>
                            <p className="text-gray-500 text-lg">
                                {isTrashView 
                                    ? 'Các mục trong thùng rác có thể được khôi phục hoặc xóa vĩnh viễn.' 
                                    : <>Chào mừng trở lại, bạn có <span className="font-semibold text-gray-900">{notes.length}</span> ghi chú.</>
                                }
                            </p>
                        </div>
                        {/* Empty Trash Button Removed from top right */}
                    </div>
                )}
                </div>

                {/* Folders Section - Only show when NOT viewing a specific folder */}
                {!viewingFolder && (
                    <section>
                    {/* Header - Hidden in Trash View */}
                    {!isTrashView && (
                        <div className="flex items-center justify-between mb-8">
                            <h2 className="text-xl font-semibold text-gray-800 flex items-center gap-2">
                            <Folder size={20} className="text-blue-500" />
                            Thư mục
                            </h2>
                        </div>
                    )}

                    {/* Grid Layout: Adjusted for wider frames (3 cols on large instead of 4) */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">

                        {/* System/Uncategorized Folder - Only show if not Trash View */}
                        {!isTrashView && (
                            <div 
                                onClick={() => setViewingFolder('Chung')}
                                className="bg-gradient-to-b from-[#f1f1f1] to-gray-200 p-8 rounded-[2rem] hover:scale-[1.02] transition-all duration-300 cursor-pointer group flex flex-col justify-between h-64 border border-white/60 relative overflow-hidden"
                            >
                                <div className="flex justify-between items-start z-10">
                                        {/* Icon Left */}
                                    <div className="w-14 h-14 rounded-2xl bg-white/80 backdrop-blur-sm text-gray-500 flex items-center justify-center">
                                        <Folder size={28} strokeWidth={2} />
                                    </div>
                                </div>

                                <div className="flex justify-between items-end z-10">
                                        {/* Title Left */}
                                    <div>
                                        <h3 className="text-2xl font-bold text-gray-800 truncate mb-1">Chung</h3>
                                        <p className="text-base text-gray-500 font-medium">Mặc định</p>
                                    </div>

                                    {/* Count Right */}
                                    <span className="text-4xl font-bold text-gray-800/80">{folderStats.uncategorized}</span>
                                </div>
                            </div>
                        )}

                        {/* User Folders */}
                        {folderStats.mapped.map((folder) => {
                        const IconComponent = ICON_MAP[folder.icon] || Folder;
                        const colorName = folder.color.split('-')[1] || 'gray';
                        const toColorClass = GRADIENT_MAP[colorName] || 'to-gray-100';
                        const iconColorClass = TEXT_COLOR_MAP[colorName] || 'text-gray-600';

                        const isMenuOpen = openMenuFolderId === folder.id;

                        return (
                            <div 
                            key={folder.id} 
                            onClick={() => !isTrashView && setViewingFolder(folder.name)}
                            className={`bg-gradient-to-b from-[#f1f1f1] ${toColorClass} p-8 rounded-[2rem] hover:scale-[1.02] transition-all duration-300 cursor-pointer group relative flex flex-col justify-between h-64 border border-white/60`}
                            >
                                {/* Top Row */}
                                <div className="flex justify-between items-start">
                                    {/* Icon Left */}
                                    <div className={`w-14 h-14 rounded-2xl bg-white/60 backdrop-blur-sm ${iconColorClass} flex items-center justify-center group-hover:scale-105 transition-transform`}>
                                        <IconComponent size={28} strokeWidth={2} />
                                    </div>

                                    {/* Menu Button Right or Restore */}
                                    <div className="relative">
                                        {isTrashView ? (
                                            <button 
                                                onClick={(e) => handleRestoreClick(e, 'folder', folder.id)}
                                                className="p-2 rounded-full hover:bg-white/80 text-green-600 bg-white/50"
                                                title="Khôi phục"
                                            >
                                                <RotateCcw size={24} />
                                            </button>
                                        ) : (
                                            <>
                                                <button 
                                                    onClick={(e) => toggleMenu(e, folder.id)}
                                                    className={`p-2 rounded-full hover:bg-white/80 transition-colors ${isMenuOpen ? 'bg-white/80 text-gray-800' : 'text-gray-400 hover:text-gray-600'}`}
                                                >
                                                    <MoreHorizontal size={24} />
                                                </button>

                                                {/* Dropdown Menu */}
                                                {isMenuOpen && (
                                                    <div ref={menuRef} className="absolute top-full right-0 mt-2 w-48 bg-white rounded-xl border border-gray-100 overflow-hidden z-20 animate-in fade-in zoom-in-95 duration-100 shadow-xl">
                                                        <button 
                                                            onClick={(e) => handleEditClick(e, folder)}
                                                            className="w-full text-left px-5 py-3.5 text-[15px] text-gray-700 hover:bg-gray-50 flex items-center gap-3 font-medium"
                                                        >
                                                            <PenLine size={18} /> Chỉnh sửa
                                                        </button>
                                                        <div className="h-px bg-gray-100 w-full"></div>
                                                        <button 
                                                            onClick={(e) => handleDeleteClick(e, folder.id)}
                                                            className="w-full text-left px-5 py-3.5 text-[15px] text-red-600 hover:bg-red-50 flex items-center gap-3 font-medium"
                                                        >
                                                            <Trash2 size={18} /> Xóa
                                                        </button>
                                                    </div>
                                                )}
                                            </>
                                        )}
                                    </div>
                                </div>

                                {/* Bottom Row */}
                                <div className="flex justify-between items-end">
                                    {/* Title Left */}
                                    <div>
                                        <h3 className="text-2xl font-bold text-gray-900 truncate pr-2 mb-1 max-w-[180px]">{folder.name}</h3>
                                        <p className="text-base text-gray-500 font-medium">{folder.count} ghi chú</p>
                                    </div>

                                    {/* Count Right - Large Number */}
                                    <span className="text-4xl font-bold text-gray-800/80">{folder.count}</span>
                                </div>
                            </div>
                        );
                        })}

                        {/* Add Folder Button - Hidden in Trash View */}
                        {!isTrashView && (
                            <div 
                                onClick={() => handleOpenModal()}
                                className="bg-[#fafafa] border-2 border-dashed border-gray-200 rounded-[2rem] p-8 flex flex-col items-center justify-center text-gray-400 hover:border-blue-300 hover:text-blue-500 hover:bg-blue-50/30 transition-all cursor-pointer h-64 gap-4 group"
                            >
                                <div className="w-16 h-16 rounded-full bg-white border border-gray-100 group-hover:bg-blue-100 group-hover:border-blue-200 flex items-center justify-center transition-colors">
                                    <Plus size={32} />
                                </div>
                                <span className="font-semibold text-lg">Thư mục mới</span>
                            </div>
                        )}
                    </div>
                    </section>
                )}

                {/* Notes Grid Section */}
                <section>
                {/* Header - Hidden in Trash View */}
                {!isTrashView && (
                    <div className="flex items-center justify-between mb-6">
                        <h2 className="text-xl font-semibold text-gray-800 flex items-center gap-2">
                        <Clock size={20} className="text-orange-500" />
                        {viewingFolder ? `Ghi chú trong "${viewingFolder}"` : 'Tất cả ghi chú'}
                        </h2>
                    </div>
                )}

                {displayedNotes.length === 0 ? (
                    <div className="text-center py-16 bg-white rounded-3xl border border-gray-100">
                        <FileText className="w-16 h-16 text-gray-200 mx-auto mb-4" />
                        <p className="text-gray-400 text-lg">Không có ghi chú nào</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                    {displayedNotes.map((note) => (
                        <div 
                        key={note.id}
                        onClick={() => !isTrashView && onSelectNote(note.id)}
                        className={`bg-white p-6 rounded-3xl border border-gray-100 hover:-translate-y-1 transition-all flex flex-col h-56 group relative ${!isTrashView ? 'cursor-pointer hover:shadow-lg' : ''}`}
                        >
                        <div className="flex justify-between items-start mb-4">
                            <span className="text-[11px] font-bold tracking-wider text-gray-400 uppercase bg-gray-50 px-2 py-1 rounded-md max-w-[120px] truncate">
                                {note.folder || 'Chung'}
                            </span>
                            <span className="text-xs text-gray-400 font-medium">{formatDate(note.updatedAt)}</span>
                        </div>

                        <h3 className="font-bold text-xl text-gray-900 mb-3 truncate pr-2 group-hover:text-blue-600 transition-colors">
                            {note.title || 'Ghi chú chưa đặt tên'}
                        </h3>

                        <p className="text-gray-500 text-sm line-clamp-4 leading-relaxed flex-1">
                            {note.content || <span className="italic opacity-50">Không có nội dung...</span>}
                        </p>

                        {isTrashView ? (
                            <div className="mt-4 pt-4 border-t border-gray-50 flex justify-end gap-2">
                                <button 
                                    onClick={(e) => handleRestoreClick(e, 'note', note.id)}
                                    className="text-green-600 text-sm font-medium hover:underline"
                                >
                                    Khôi phục
                                </button>
                            </div>
                        ) : (
                            <div className="mt-4 pt-4 border-t border-gray-50 flex justify-end text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                <span className="text-xs font-semibold flex items-center">
                                    Mở ghi chú <ChevronRight size={14} className="ml-1" />
                                </span>
                            </div>
                        )}
                        </div>
                    ))}
                    </div>
                )}
                </section>
            </div>
        </div>

        {/* Empty Trash Button - Floating at bottom center, Bigger, Icon Only */}
        {isTrashView && (notes.length > 0 || folders.length > 0) && (
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-30">
                <button 
                    onClick={onEmptyTrash}
                    className="w-20 h-20 bg-red-500 hover:bg-red-600 text-white rounded-full shadow-2xl shadow-red-500/40 flex items-center justify-center transition-all hover:scale-110 active:scale-95 group"
                    title="Dọn sạch thùng rác"
                >
                    <Trash2 size={32} strokeWidth={2.5} className="group-hover:rotate-12 transition-transform" />
                </button>
            </div>
        )}

      {/* MODAL for Create/Edit Folder */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/20 backdrop-blur-sm">
          <div className="bg-white rounded-3xl w-full max-w-md p-8 animate-in fade-in zoom-in duration-200 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-bold text-gray-900">
                {editingFolderId ? 'Sửa thư mục' : 'Thư mục mới'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 p-2 rounded-full hover:bg-gray-100">
                <X size={24} />
              </button>
            </div>

            <div className="space-y-8">
              {/* Name Input */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Tên thư mục</label>
                <input 
                  type="text" 
                  value={folderName}
                  onChange={(e) => setFolderName(e.target.value)}
                  placeholder="Ví dụ: Du lịch, Ý tưởng..."
                  className="w-full px-5 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all text-lg"
                  autoFocus
                />
              </div>

              {/* Color Picker with Gradient Preview */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Màu sắc</label>
                <div className="grid grid-cols-7 gap-3">
                  {COLOR_OPTIONS.map((color) => {
                    const colorName = color.id;
                    const toColorClass = GRADIENT_MAP[colorName];
                    return (
                        <button
                        key={color.id}
                        onClick={() => setSelectedColor(color.class)}
                        className={`w-full aspect-square rounded-full bg-gradient-to-b from-[#f1f1f1] ${toColorClass} transition-transform hover:scale-110 border-2 ${selectedColor === color.class ? 'border-gray-400 scale-110' : 'border-transparent'}`}
                        title={colorName}
                        />
                    );
                  })}
                </div>
              </div>

              {/* Icon Picker */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Biểu tượng</label>
                <div className="grid grid-cols-5 gap-3">
                  {Object.entries(ICON_MAP).map(([name, Icon]) => (
                    <button
                      key={name}
                      onClick={() => setSelectedIcon(name)}
                      className={`p-3 rounded-2xl flex items-center justify-center transition-all ${selectedIcon === name ? 'bg-gray-100 text-gray-900 ring-2 ring-gray-200' : 'text-gray-400 hover:bg-gray-50'}`}
                    >
                      <Icon size={24} strokeWidth={2} />
                    </button>
                  ))}
