                  })}
                </div>
              </div>

              {/* Icon Picker */}
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-3 uppercase tracking-wider">Biểu tượng</label>
                <div className="grid grid-cols-5 gap-3">
                  {Object.entries(ICON_MAP).map(([name, Icon]) => (
                    <button
