           {/* Home Button Right */}
           <button 
             onClick={onGoHome}
             className={`p-2 rounded-xl transition-all ${currentView === 'dashboard' && activeNoteId === null ? 'bg-yellow-100 text-yellow-600' : 'text-gray-400 hover:bg-gray-100 hover:text-yellow-600'}`}
             title="Trang chủ"
           >
               <House size={20} />
           </button>
        </div>
      </div>

      {/* Note List */}
      <div className="flex-1 overflow-y-auto no-scrollbar px-4 pb-4">
        {sortedAndFilteredNotes.length === 0 ? (
          <div className="p-8 text-center text-gray-400">
            <p className="text-sm">
                {currentView === 'trash' ? 'Thùng rác trống' : 'Không tìm thấy ghi chú nào.'}
            </p>
          </div>
        ) : (
          <ul className="space-y-2">
            {sortedAndFilteredNotes.map((note) => (
              <li
                key={note.id}
                onClick={() => onSelectNote(note.id)}
                className={`group relative cursor-pointer p-4 rounded-2xl transition-all duration-200 ${
                  activeNoteId === note.id 
                    ? 'bg-white shadow-sm ring-1 ring-black/5 z-10' 
                    : 'hover:bg-white/60'
