                                onClick={onGoTrash}
                                className="bg-gradient-to-b from-[#f1f1f1] to-red-100 p-8 rounded-[2rem] hover:scale-[1.02] transition-all duration-300 cursor-pointer group flex flex-col justify-between h-64 border border-white/60 relative overflow-hidden"
                            >
                                <div className="flex justify-between items-start z-10">
                                    <div className="w-14 h-14 rounded-2xl bg-white/80 backdrop-blur-sm text-red-500 flex items-center justify-center">
                                        <Trash2 size={28} strokeWidth={2} />
