                <div className={`absolute bottom-full mb-4 left-1/2 -translate-x-1/2 flex flex-col gap-2 transition-all duration-200 ${showCreateMenu ? 'opacity-100 translate-y-0 pointer-events-auto' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
