                <button 
                    className={`w-18 h-18 md:w-20 md:h-20 rounded-full shadow-2xl shadow-yellow-500/20 hover:shadow-[0_0_30px_-5px_rgba(250,204,21,0.6)] flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95 ${showCreateMenu ? 'bg-yellow-400 text-white' : 'bg-yellow-400 text-white'}`}
                >
                    <Plus size={36} strokeWidth={2.5} className="transition-transform duration-300" />
